33	export default function HabitsPage() {
34	  const [habits, setHabits] = useState<Habit[]>([]);
35	  const [loading, setLoading] = useState(true);
36	  const [showForm, setShowForm] = useState(false);
37	  const [editId, setEditId] = useState<string | null>(null);
38	  const [form, setForm] = useState({
39	    title: "", description: "", domainIdx: 0, unit: "次",
40	    targetValue: 1, frequency: "daily",
41	  });
42	
43	  // Domain management state
44	  const [showDomainManager, setShowDomainManager] = useState(false);
45	  const [domainManagerView, setDomainManagerView] = useState<"list" | "new" | "edit">("list");
46	  const [domainForm, setDomainForm] = useState<Domain>({ name: "", icon: "dumbbell", color: "#ef4444" });
47	  const [editingDomainName, setEditingDomainName] = useState<string | null>(null);
48	  const [saving, setSaving] = useState(false);
49	  const [formDirty, setFormDirty] = useState(false);
50	
51	  useDidShow(() => { fetchHabits(); });
52	
53	  async function fetchHabits() {
54	    try {
55	      setHabits(await apiFetch("/api/habits"));
56	    } catch (e: any) {
57	      console.error("[fetchHabits]", e);
58	      showToast({ title: "获取习惯列表失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
59	    }
60	    setLoading(false);
61	  }
62	
63	  function openNew() {
64	    setEditId(null);
65	    setForm({ title: "", description: "", domainIdx: 0, unit: "次", targetValue: 1, frequency: "daily" });
66	    setFormDirty(false);
67	    setShowForm(true);
68	  }
69	
70	  function openEdit(h: Habit) {
71	    setEditId(h.id);
72	    const domains = getDomains();
73	    const idx = domains.findIndex(d => d.name === h.domainId);
74	    setForm({
75	      title: h.title,
76	      description: h.description || "",
77	      domainIdx: idx >= 0 ? idx : domains.length - 1,
78	      unit: h.unit,
79	      targetValue: h.targetValue,
80	      frequency: h.frequency,
81	    });
82	    setFormDirty(false);
83	    setShowForm(true);
84	  }
85	
86	  async function handleSave() {
87	    const domains = getDomains();
88	    if (form.domainIdx < 0 || form.domainIdx >= domains.length) {
89	      showToast({ title: "领域索引无效", icon: "none" });
90	      return;
91	    }
92	    setSaving(true);
93	    try {
94	      const body = { ...form, domainId: domains[form.domainIdx].name };
95	      if (editId) {
96	        await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: editId, ...body }) });
97	      } else {
98	        await apiFetch("/api/habits", { method: "POST", body: JSON.stringify(body) });
99	      }
100	      setShowForm(false);
101	      setFormDirty(false);
102	      fetchHabits();
103	    } catch (e: any) {
104	      console.error("[handleSave]", e);
105	      showToast({ title: "保存习惯失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
106	    } finally {
107	      setSaving(false);
108	    }
109	  }
110	
111	  async function handleCloseForm() {
112	    if (formDirty) {
113	      const res = await showModal({ title: "确认关闭", content: "当前填写的内容尚未保存，确定要关闭吗？" });
114	      if (!res.confirm) return;
115	    }
116	    setShowForm(false);
117	    setFormDirty(false);
118	  }
119	
120	  async function deleteHabit(id: string) {
121	    try {
122	      await apiFetch("/api/habits", { method: "DELETE", body: JSON.stringify({ id }) });
123	      fetchHabits();
124	    } catch (e: any) {
125	      console.error("[deleteHabit]", e);
126	      showToast({ title: "删除习惯失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
127	    }
128	  }
129	
130	  async function toggleActive(id: string, current: boolean) {
131	    try {
132	      await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id, isActive: !current }) });
133	      fetchHabits();
134	    } catch (e: any) {
135	      console.error("[toggleActive]", e);
136	      showToast({ title: "操作失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
137	    }
138	  }
139	
140	  // ---- Domain management handlers ----
141	
142	  function openDomainManager() {
143	    setShowForm(false);
144	    setDomainManagerView("list");
145	    setDomainForm({ name: "", icon: "dumbbell", color: "#ef4444" });
146	    setEditingDomainName(null);
147	    setShowDomainManager(true);
148	  }
149	
150	  function openNewDomain() {
151	    setDomainForm({ name: "", icon: "dumbbell", color: "#ef4444" });
152	    setDomainManagerView("new");
153	  }
154	
155	  function openEditDomain(domain: Domain) {
156	    setEditingDomainName(domain.name);
157	    setDomainForm({ name: domain.name, icon: domain.icon, color: domain.color });
158	    setDomainManagerView("edit");
159	  }
160	
161	  async function handleDomainSave() {
162	    const name = domainForm.name.trim();
163	    if (!name) return;
164	
165	    const userDomains = getDomains().filter(d => d.name !== UNCATEGORIZED.name);
166	
167	    if (domainManagerView === "new") {
168	      if (userDomains.some(d => d.name === name)) {
